import express from 'express';
import { Autumn } from 'autumn-js';

const app = express();
app.use(express.json());

const autumnSecretKey = process.env.AUTUMN_SECRET_KEY;
if (!autumnSecretKey) {
  throw new Error('AUTUMN_SECRET_KEY is required');
}

const autumn = new Autumn({ secretKey: autumnSecretKey });

const requireFields = (res, payload, fields) => {
  const missing = fields.filter((field) => !payload?.[field]);
  if (missing.length > 0) {
    res.status(400).json({ error: 'Missing required fields', missing });
    return false;
  }
  return true;
};

app.get('/health', (req, res) => {
  res.json({ status: 'ok' });
});

app.post('/workspaces', async (req, res) => {
  const { customerId, workspaceId, featureId, name } = req.body;
  if (!requireFields(res, req.body, ['customerId', 'workspaceId', 'featureId'])) {
    return;
  }

  try {
    const workspace = await autumn.entities.create({
      customerId,
      entityId: workspaceId,
      featureId,
      name: name ?? null,
    });

    res.status(201).json({ workspace });
  } catch (error) {
    res.status(500).json({ error: 'Failed to create workspace', details: error?.message });
  }
});

app.post('/workspaces/:workspaceId/use-credits', async (req, res) => {
  const { workspaceId } = req.params;
  const { customerId, featureId, amount, properties } = req.body;

  if (!requireFields(res, req.body, ['customerId', 'featureId', 'amount'])) {
    return;
  }

  try {
    const result = await autumn.check({
      customerId,
      featureId,
      entityId: workspaceId,
      requiredBalance: amount,
      sendEvent: true,
      properties,
    });

    res.json({ allowed: result.allowed, balance: result.balance });
  } catch (error) {
    res.status(500).json({ error: 'Failed to consume credits', details: error?.message });
  }
});

app.get('/workspaces/:workspaceId/balance', async (req, res) => {
  const { workspaceId } = req.params;
  const { customerId, featureId } = req.query;

  if (!requireFields(res, req.query, ['customerId', 'featureId'])) {
    return;
  }

  try {
    const result = await autumn.check({
      customerId,
      featureId,
      entityId: workspaceId,
      requiredBalance: 0,
      sendEvent: false,
    });

    res.json({ balance: result.balance, allowed: result.allowed });
  } catch (error) {
    res.status(500).json({ error: 'Failed to fetch balance', details: error?.message });
  }
});

app.delete('/workspaces/:workspaceId', async (req, res) => {
  const { workspaceId } = req.params;
  const { customerId } = req.query;

  if (!requireFields(res, req.query, ['customerId'])) {
    return;
  }

  try {
    const result = await autumn.entities.delete({
      customerId,
      entityId: workspaceId,
    });

    res.json({ deleted: result.deleted });
  } catch (error) {
    res.status(500).json({ error: 'Failed to delete workspace', details: error?.message });

